<body>
    <div class="app-data-container">$1</div>
    <div class="phone-frame">
        <div class="app-header">
            <div class="title">Bắn Ra</div>
            <div class="actions">
                <button id="search-btn"><i class="fa-solid fa-magnifying-glass"></i>Tìm kiếm</button>
                <button id="refresh-btn"><i class="fa-solid fa-arrows-rotate"></i>Làm mới</button>
            </div>
        </div>
        <div class="app-content" id="app-content">

        </div>
    </div>

    <script>
    document.addEventListener('DOMContentLoaded', () => {
        const dataContainer = document.querySelector('.app-data-container');
        const contentArea = document.getElementById('app-content');
        const appData = { shops: [] };
        let currentView = 'shops';
        let currentShopIndex = -1;

        function sendSillyTavernCommand(commandObject) {
            const commandChain = [];
            if (commandObject.vars) {
                for (const key in commandObject.vars) {
                    const value = String(commandObject.vars[key]).replace(/"/g, '\\"');
                    commandChain.push(`/setvar key="${key}" value="${value}"`);
                }
            }
            if (commandObject.send) {
                const message = commandObject.send.replace(/"/g, '\\"');
                commandChain.push(`/send "${message}"`);
            }
            commandChain.push('/trigger await=true');
            const finalCommand = commandChain.join(' | ');

            if (typeof triggerSlash === 'function') {
                triggerSlash(finalCommand);
            } else {
                console.error("Không tìm thấy hàm triggerSlash của SillyTavern.");
                alert(`Mô phỏng gửi lệnh (vui lòng chạy trong môi trường SillyTavern):\n${finalCommand}`);
            }
        }

        function parseBlockList(content, key) {
            const lines = content.split('\n');
            const result = [];
            let inList = false;
            for (const line of lines) {
                if (line.trim().startsWith(key + ':')) {
                    inList = true;
                    continue;
                }
                if (inList) {
                    const trimmedLine = line.trim();
                    if (trimmedLine.startsWith('- ')) {
                        let cleaned = trimmedLine.substring(2);
                        if (key === 'reviews' && cleaned.startsWith('"') && cleaned.endsWith('"')) {
                            cleaned = cleaned.slice(1, -1);
                        }
                        result.push(cleaned);
                    } else if (trimmedLine !== '' && /^\w+:/.test(trimmedLine)) {
                        inList = false;
                    }
                }
            }
            return result;
        }

        function parseData(text) {
            const shopRegex = /\[店铺\]([\s\S]*?)\[\/店铺\]/g;
            let shopMatch;
            while ((shopMatch = shopRegex.exec(text)) !== null) {
                const shopContent = shopMatch[1];
                const shop = { packages: [] };
                shop.name = shopContent.match(/name: (.*)/)?.[1].trim() || 'Cửa hàng không xác định';
                shop.stars = parseFloat(shopContent.match(/stars: (.*)/)?.[1] || 0);
                shop.tags = parseBlockList(shopContent, 'shoptags');
                const packageRegex = /\[套餐\]([\s\S]*?)\[\/套餐\]/g;
                let packageMatch;
                while((packageMatch = packageRegex.exec(shopContent)) !== null) {
                    const pkgContent = `\n${packageMatch[1]}`;
                    const pkg = {};
                    pkg.name = pkgContent.match(/\nname: (.*)/)?.[1].trim() || 'Gói không xác định';
                    pkg.price = pkgContent.match(/\nprice: (.*)/)?.[1].trim() || '¥??';
                    pkg.stars = parseFloat(pkgContent.match(/\nstars: (.*)/)?.[1] || 0);
                    pkg.description = pkgContent.match(/\ndescription: ([\s\S]*?)(?=\ncontent:)/)?.[1].trim() || '';
                    pkg.images = [];
                    for(let i = 1; i <= 3; i++){
                        const imgRegex = new RegExp(`\\nimage${i}: ([\\s\\S]*?)(?=\\nimage${i+1}|\\ndescription:)`);
                        const imgMatch = pkgContent.match(imgRegex);
                        if(imgMatch) pkg.images.push(imgMatch[1].trim());
                    }
                    pkg.tags = parseBlockList(pkgContent, 'tags');
                    pkg.content = parseBlockList(pkgContent, 'content');
                    pkg.reviews = parseBlockList(pkgContent, 'reviews');
                    shop.packages.push(pkg);
                }
                appData.shops.push(shop);
            }
        }

        function renderStars(rating){
            let starsHTML = '';
            for(let i = 1; i <= 5; i++){
                if(i <= rating) starsHTML += '<i class="fa-solid fa-star"></i>';
                else if (i - rating < 1) starsHTML += '<i class="fa-solid fa-star-half-stroke"></i>';
                else starsHTML += '<i class="fa-regular fa-star"></i>';
            }
            return `${starsHTML} ${rating.toFixed(1)}`;
        }

        function renderShops() {
            contentArea.innerHTML = '';
            appData.shops.forEach((shop, index) => {
                const card = document.createElement('div');
                card.className = 'shop-card';
                card.innerHTML = `
                    <div class="card-header">
                        <h3 class="card-title">${shop.name}</h3>
                        <div class="card-stars">${renderStars(shop.stars)}</div>
                    </div>
                    <div class="card-tags">${shop.tags.map(t => `<span class="tag">${t}</span>`).join('')}</div>
                `;
                card.onclick = () => renderPackages(index);
                contentArea.appendChild(card);
            });
            currentView = 'shops';
        }

        function renderPackages(shopIndex) {
            currentShopIndex = shopIndex;
            const shop = appData.shops[shopIndex];
            contentArea.innerHTML = `
                <button class="back-button" onclick="window.renderShops()"><i class="fa-solid fa-arrow-left"></i> Quay lại danh sách cửa hàng</button>
            `;
            shop.packages.forEach((pkg, index) => {
                const card = document.createElement('div');
                card.className = 'package-card';
                card.innerHTML = `
                    <div class="card-header">
                        <h3 class="card-title">${pkg.name}</h3>
                        <div class="card-price">${pkg.price}</div>
                    </div>
                    <div class="card-tags">${pkg.tags.map(t => `<span class="tag">${t}</span>`).join('')}</div>
                    <div class="card-stars" style="text-align: right; margin-top: 8px;">${renderStars(pkg.stars)}</div>
                `;
                card.onclick = () => renderDetails(shopIndex, index);
                contentArea.appendChild(card);
            });
            currentView = 'packages';
        }

        function renderDetails(shopIndex, pkgIndex) {
            const pkg = appData.shops[shopIndex].packages[pkgIndex];
            contentArea.innerHTML = `
                <div class="detail-view">
                    <button class="back-button" onclick="window.renderPackages(${shopIndex})"><i class="fa-solid fa-arrow-left"></i> Quay lại danh sách gói</button>
                    ${pkg.images.length > 0 ? `
                    <div class="image-carousel">
                        <div class="carousel-images">
                           ${pkg.images.map((img, i) => `<div class="carousel-image-description ${i === 0 ? 'active' : ''}"><strong>Ảnh ${i + 1}:</strong>${img}</div>`).join('')}
                        </div>
                        <div class="carousel-nav">
                            <button class="prev-btn"><i class="fa-solid fa-chevron-left"></i></button>
                            <button class="next-btn"><i class="fa-solid fa-chevron-right"></i></button>
                        </div>
                        <div class="image-dots"></div>
                    </div>` : ''}
                    <div class="detail-content-card">
                        <div class="detail-header">
                            <h3 class="detail-title">${pkg.name}</h3>
                            <div class="detail-price">${pkg.price}</div>
                        </div>
                        <div class="detail-section">
                            <h4 class="section-title">Mô tả sản phẩm</h4>
                            <p class="detail-description">${pkg.description}</p>
                        </div>
                         <div class="detail-section">
                            <h4 class="section-title">Thẻ hương vị</h4>
                            <div class="card-tags">${pkg.tags.map(t => `<span class="tag">${t}</span>`).join('')}</div>
                        </div>
                        <div class="detail-section">
                            <h4 class="section-title">Nội dung gói</h4>
                            <div class="detail-content"><ul>${pkg.content.map(c => `<li>${c}</li>`).join('')}</ul></div>
                        </div>
                    </div>
                    <div class="detail-content-card" style="margin-top: 10px;">
                        <div class="detail-section" style="margin-top:0;">
                            <h4 class="section-title">Đánh giá</h4>
                            <div class="reviews">${pkg.reviews.map(r => `<div class="review">${r}</div>`).join('') || '<p>Chưa có đánh giá</p>'}</div>
                        </div>
                    </div>
                </div>
                <div class="order-button-container">
                    <button class="order-button">Đặt hàng ngay</button>
                </div>
            `;

            let currentImage = 0;
            const images = contentArea.querySelectorAll('.carousel-image-description');
            const dotsContainer = contentArea.querySelector('.image-dots');

            if (images.length > 1) {
                for (let i = 0; i < images.length; i++) {
                    const dot = document.createElement('span');
                    dot.className = 'dot';
                    dot.onclick = () => showImage(i);
                    dotsContainer.appendChild(dot);
                }
                const dots = dotsContainer.querySelectorAll('.dot');
                function showImage(index) {
                    images[currentImage].classList.remove('active');
                    dots[currentImage].classList.remove('active');
                    currentImage = (index + images.length) % images.length;
                    images[currentImage].classList.add('active');
                    dots[currentImage].classList.add('active');
                }
                showImage(0);
                contentArea.querySelector('.next-btn').onclick = () => showImage(currentImage + 1);
                contentArea.querySelector('.prev-btn').onclick = () => showImage(currentImage - 1);
            } else if (images.length === 1) {
                contentArea.querySelector('.carousel-nav').style.display = 'none';
                contentArea.querySelector('.image-dots').style.display = 'none';
            }

            contentArea.querySelector('.order-button').onclick = () => {
                const remarks = prompt(`Thêm ghi chú cho gói “${pkg.name}” (có thể để trống):`, '');
                if (remarks === null) return;
                const commandText = `Tôi đã đặt hàng “${pkg.name}”.\nGhi chú: ${remarks === '' ? 'Không có' : remarks}`;
                sendSillyTavernCommand({
                    send: commandText,
                    vars: { ordered_item: pkg.name, order_remarks: remarks === '' ? 'Không có' : remarks }
                });
            };
            currentView = 'details';
        }

        window.renderShops = renderShops;
        window.renderPackages = renderPackages;
        window.renderDetails = renderDetails;

        const rawData = dataContainer.textContent.trim();
        if (rawData) {
            parseData(rawData);
            renderShops();
        } else {
            contentArea.innerHTML = '<p style="text-align:center; color: var(--text-light); padding:20px;">Chưa có dữ liệu, vui lòng làm mới.</p>';
        }

        document.getElementById('refresh-btn').onclick = () => sendSillyTavernCommand({ send: 'Làm mới trang chủ' });
        document.getElementById('search-btn').onclick = () => {
            const keyword = prompt('Vui lòng nhập từ khóa tìm kiếm (ví dụ: giáo viên, loli, quý cô):', '');
            if(keyword) sendSillyTavernCommand({ send: `Tìm kiếm: ${keyword}` });
        };
    });
    </script>
</body>
</html>
