                updateElementText('char-body-chest', safeGetValue(data, '角色.身体.胸部'));
                updateElementText('char-body-private', safeGetValue(data, '角色.身体.私处'));
                updateElementText('char-body-buttocks', safeGetValue(data, '角色.身体.臀部'));
                updateElementText('char-body-legs', safeGetValue(data, '角色.身体.腿脚'));


            } catch (error) {
                console.error('Lỗi khi tải thanh trạng thái:', error);
                document.getElementById('app-content').innerHTML = `<p style='color:red; padding:10px;'>Lỗi khi tải thanh trạng thái: ${error.message}</p>`;
            }
        }

        document.getElementById('home-btn').onclick = () => {
             sendSillyTavernCommand('/send "Xem trang chủ APP" | /trigger await=true');
        };

        document.getElementById('search-btn-footer').onclick = () => {
            const keyword = prompt('Vui lòng nhập từ khóa tìm kiếm:', '');
            if (keyword) {
                 sendSillyTavernCommand(`/send "Tìm kiếm: ${keyword.replace(/"/g, '\\"')}" | /trigger await=true`);
            }
        };

        document.addEventListener('DOMContentLoaded', initDisplay);

    </script>
</body>
